mapper.select:

where del_flag = '0'
  and license_kind_code = #{licenseKindCode}
  and license_no = #{licenseNo}
  and exists (
      select 1 from scm_product_certificate c
      where cast(c.certificate_id as char) = scm_product_cert_license_snap.certificate_id
        and c.supplier_id = #{supplierId}


                and c.hospital_id = #{hospitalId}


                and c.hospital_code = #{hospitalCode}


                and 1 = 0


  )
